@page "/track"

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHT-20260529-123456)"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null && !isLoading)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>. Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Tracking: @shipment.TrackingNumber</h5>
            <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>

                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMMM d, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd class="fw-bold text-primary">@shipment.EstimatedDelivery.ToString("MMMM d, yyyy")</dd>

                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Delivered On</dt>
                            <dd class="text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMMM d, yyyy")</dd>
                        }

                        <dt>Carrier</dt>
                        <dd>@shipment.CarrierName</dd>

                        <dt>Weight</dt>
                        <dd>@shipment.WeightKg.ToString("F1") kg</dd>
                    </dl>
                </div>
            </div>

            <h6 class="mt-3">Delivery Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgressPercent(shipment.Status))%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0"
                     aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool isLoading;
    private bool searched;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        searched = false;
        shipment = null;

        try
        {
            searchedNumber = trackingNumber.Trim();
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
            searched = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        ShipmentStatus.Returned => 100,
        _ => 0
    };
}

@page "/shipments"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Shipments Dashboard</PageTitle>

<h1>Shipments Dashboard</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div class="d-flex gap-2">
        <input type="text" class="form-control" style="width: 250px;"
               placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
        <select class="form-select" style="width: 180px;" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <button class="btn btn-primary" @onclick="() => showCreateForm = !showCreateForm">
        @(showCreateForm ? "Cancel" : "+ New Shipment")
    </button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header"><h5 class="mb-0">Create New Shipment</h5></div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Recipient Name</label>
                    <input type="text" class="form-control" @bind="newShipment.RecipientName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Carrier</label>
                    <input type="text" class="form-control" @bind="newShipment.CarrierName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Weight (kg)</label>
                    <input type="number" class="form-control" step="0.1" @bind="newShipment.WeightKg" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Shipped Date</label>
                    <input type="date" class="form-control" @bind="newShipment.ShippedDate" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-12">
                    <button class="btn btn-success" @onclick="CreateShipment" disabled="@isSaving">
                        @if (isSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Create Shipment
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@if (isLoading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Carrier</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Status</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td>@s.CarrierName</td>
                        <td>@s.ShippedDate.ToString("yyyy-MM-dd")</td>
                        <td>@s.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>
                            <select class="form-select form-select-sm" style="width: 150px;"
                                    value="@s.Status"
                                    @onchange="e => UpdateStatus(s.Id, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status" selected="@(status == s.Status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    @if (!FilteredShipments.Any())
    {
        <div class="alert alert-info">No shipments match your filters.</div>
    }
}

@code {
    private List<ShipmentDto> shipments = [];
    private bool isLoading = true;
    private bool isSaving;
    private bool showCreateForm;
    private string? errorMessage;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private ShipmentDto newShipment = CreateEmptyShipment();

    private IEnumerable<ShipmentDto> FilteredShipments => shipments.Where(s =>
    {
        if (!string.IsNullOrWhiteSpace(filterText) &&
            !s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
            return false;

        if (!string.IsNullOrWhiteSpace(statusFilter) &&
            Enum.TryParse<ShipmentStatus>(statusFilter, out var status) &&
            s.Status != status)
            return false;

        return true;
    });

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            shipments = await ShipmentService.GetShipmentsAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task CreateShipment()
    {
        isSaving = true;
        try
        {
            await ShipmentService.CreateShipmentAsync(newShipment);
            newShipment = CreateEmptyShipment();
            showCreateForm = false;
            await LoadShipments();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create shipment: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var status))
        {
            try
            {
                await ShipmentService.UpdateShipmentStatusAsync(id, status);
                await LoadShipments();
            }
            catch (Exception ex)
            {
                errorMessage = $"Failed to update status: {ex.Message}";
            }
        }
    }

    private static ShipmentDto CreateEmptyShipment() => new()
    {
        ShippedDate = DateTime.UtcNow,
        EstimatedDelivery = DateTime.UtcNow.AddDays(5)
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}

